"""Базовый оверлей-модалка: затемнённый фон, карточка по центру."""from __future__ import annotationsimport tkinter as tkfrom tkinter import ttkfrom src.gui.template.styles import (    MODAL_CARD_MIN_HEIGHT,    MODAL_CARD_PADX,    MODAL_CARD_PADY_BOTTOM,    MODAL_CARD_PADY_TOP,    MODAL_CARD_WIDTH,    PALETTE,)class OverlayModalBase(ttk.Frame):    """Базовый оверлей: затемнённый фон, блокировка кликов, карточка по центру.    Карточка без внутренних панелей, единый стиль по PALETTE.    Подклассы переопределяют _build_content(card) для своего содержимого.    """    def __init__(self, parent: tk.Misc, **kwargs) -> None:        super().__init__(parent, **kwargs)        self._card: tk.Frame | None = None        self._shade: tk.Frame | None = None        self._build_overlay()        self.place_forget()        self.bind("<Button-1>", lambda _e: "break")    def _build_overlay(self) -> None:        p = PALETTE        self._shade = tk.Frame(self, bg=p["bg_main"], cursor="arrow")        self._shade.place(relx=0, rely=0, relwidth=1, relheight=1)        self._shade.bind("<Button-1>", lambda _e: "break")        self._card = tk.Frame(            self,            bg=p["bg_elevated"],            highlightthickness=1,            highlightbackground=p["border"],        )        self._content = tk.Frame(self._card, bg=p["bg_elevated"])        self._content.pack(            fill=tk.BOTH, expand=True,            padx=MODAL_CARD_PADX, pady=(MODAL_CARD_PADY_TOP, MODAL_CARD_PADY_BOTTOM),        )        self._build_content(self._content)        self._card.update_idletasks()        self._content.update_idletasks()        pady_total = MODAL_CARD_PADY_TOP + MODAL_CARD_PADY_BOTTOM        req_h = self._content.winfo_reqheight()        card_h = max(MODAL_CARD_MIN_HEIGHT, req_h + pady_total)        self._card.place(            relx=0.5, rely=0.5, anchor=tk.CENTER,            width=MODAL_CARD_WIDTH, height=card_h,        )        self._card.bind("<Button-1>", lambda _e: "break")    def _build_content(self, container: tk.Misc) -> None:        """Переопределяется в подклассах: заголовок, текст, кнопки, поля ввода."""        pass    def _update_card_height(self) -> None:        """Пересчитать высоту карточки по текущему контенту (нужно при динамическом контенте, например errors)."""        self._content.update_idletasks()        pady_total = MODAL_CARD_PADY_TOP + MODAL_CARD_PADY_BOTTOM        req_h = self._content.winfo_reqheight()        card_h = max(MODAL_CARD_MIN_HEIGHT, req_h + pady_total)        self._card.place_configure(height=card_h)    def show(self) -> None:        """Показывает модалку поверх родителя. Если родитель — слой модалок ( _is_app_modal_layer ), сначала показывается он."""        parent = self.master        if getattr(parent, "_is_app_modal_layer", False) and not parent.winfo_ismapped():            parent.place(relx=0, rely=0, relwidth=1, relheight=1)            parent.lift()        self.lift()        self.place(relx=0, rely=0, relwidth=1, relheight=1)        self._update_card_height()        self.focus_set()        toplevel = self.winfo_toplevel()        self._escape_bid = toplevel.bind("<Escape>", lambda _e: self.hide(), add="+")    def hide(self) -> None:        """Скрывает модалку. Если родитель — слой модалок и других видимых модалок нет, скрывает слой."""        toplevel = self.winfo_toplevel()        try:            toplevel.unbind("<Escape>", self._escape_bid)        except (AttributeError, tk.TclError):            pass        self.place_forget()        parent = self.master        if getattr(parent, "_is_app_modal_layer", False):            if not any(w.winfo_ismapped() for w in parent.winfo_children()):                parent.place_forget()